function solve(nums) {
    const n = nums.length;
    const ans = new Array(2 * n);

    // Fill the first half (0 <= i <= n - 1): ans[i] = nums[i]
    for (let i = 0; i < n; i++) {
        ans[i] = nums[i];
    }

    // Fill the second half (n <= i + n <= 2n - 1): ans[i + n] = nums[n - i - 1]
    // We iterate i from 0 to n-1, corresponding to the index in the reversed part.
    for (let i = 0; i < n; i++) {
        // The index in the original nums for the reversed part is n - 1 - i
        const originalIndex = n - 1 - i;
        const ansIndex = i + n;
        ans[ansIndex] = nums[originalIndex];
    }

    return ans;
}

